SELECT count(*) FROM company_type, movie_companies, title, company_name, movie_info, info_type, cast_info, role_type WHERE movie_companies.company_type_id = company_type.id AND movie_companies.movie_id = title.id AND movie_companies.company_id = company_name.id AND movie_info.movie_id = title.id AND movie_info.info_type_id = info_type.id AND cast_info.movie_id = title.id AND cast_info.role_id = role_type.id;